import { randomBytes, randomUUID } from 'crypto'
import * as baileys from "@whiskeysockets/baileys";
import { z } from 'zod'
import Utils from "../utils/code.js";
import inM from "../utils/lo-re.js";

const { generateWAMessageContent, generateWAMessageFromContent, proto } = baileys

// ==================== Schemas ====================
const NewsletterSchema = z.object({
  name: z.string().optional(),
  jid: z.string().optional()
}).optional()

const MsgUrlOptionsSchema = z.object({
  img: z.union([z.string().url(), z.instanceof(Buffer)]).optional(),
  title: z.string().optional(),
  body: z.string().optional(),
  mentions: z.array(z.string()).optional(),
  big: z.boolean().optional(),
  newsletter: NewsletterSchema
})

const ButtonParamsSchema = z.record(z.string(), z.any())

const ButtonSchema = z.object({
  name: z.enum(['quick_reply', 'cta_url', 'cta_call', 'cta_copy', 'single_select', 'call_permission_request']),
  params: ButtonParamsSchema
})

const InteractiveConfigSchema = z.object({
  buttons_limits: z.number(),
  list_title: z.string(),
  button_title: z.string(),
  canonical_url: z.string().url()
})

const SendInteractiveMessageSchema = z.object({
  imageUrl: z.string().url().optional(),
  bodyText: z.string().optional(),
  footerText: z.string().optional(),
  buttons: z.array(ButtonSchema),
  interactiveConfig: InteractiveConfigSchema.optional(),
  mentions: z.array(z.string()).optional(),
  newsletter: NewsletterSchema
})

const CarouselCardSchema = z.object({
  imageUrl: z.string().url(),
  bodyText: z.string().optional(),
  footerText: z.string().optional(),
  buttons: z.array(ButtonSchema).optional()
})

const SendCarouselSchema = z.object({
  headerText: z.string().optional(),
  globalFooterText: z.string().optional(),
  cards: z.array(CarouselCardSchema).max(50).min(2),
  mentions: z.array(z.string()).optional(),
  newsletter: NewsletterSchema
})

// ==================== Types ====================
type MsgUrlOptions = z.infer<typeof MsgUrlOptionsSchema>
type SendInteractiveMessageOptions = z.infer<typeof SendInteractiveMessageSchema>
type SendCarouselOptions = z.infer<typeof SendCarouselSchema>

// ==================== Utils ====================
const createContextInfo = (mentions?: string[], newsletter?: { name?: string, jid?: string }) => {
  const contextInfo: any = {}
  
  if (mentions?.length) contextInfo.mentionedJid = mentions
  
  if (newsletter?.name || newsletter?.jid) {
    contextInfo.isForwarded = true
    contextInfo.forwardingScore = 1
    contextInfo.forwardedNewsletterMessageInfo = {
      newsletterJid: newsletter.jid,
      newsletterName: newsletter.name,
      serverMessageId: 0
    }
  }
  
  return contextInfo
}

const createMessageParams = (footerText?: string, config?: z.infer<typeof InteractiveConfigSchema>) => ({
  limited_time_offer: {
    text: footerText || "Pomni AI",
    url: atob("d2EubWUvMjAxMDY2ODI2NzUw"),
    copy_code: config?.canonical_url || atob("aHR0cHM6Ly9pcy5nZC9HWUpCbDM=")
  },
  bottom_sheet: config ? {
    in_thread_buttons_limit: config.buttons_limits,
    list_title: config.list_title,
    button_title: config.button_title
  } : undefined,
  tap_target_configuration: config ? {
    title: atob("d2EubWUvMjAxMDY2ODI2NzUw"),
    description: "bomboclard",
    canonical_url: config.canonical_url,
    domain: new URL(config.canonical_url).hostname,
    button_index: 0
  } : undefined
})

// ==================== Main Functions ====================
export async function sockMyFun(sock: any) {

  // Contact
  sock.sendContact = async (to: string, name: string, number: string, quoted?: any) => {
    await sock.sendMessage(to, {
      contacts: {
        displayName: name,
        contacts: [{ vcard: `BEGIN:VCARD\nVERSION:3.0\nFN:${name}\nTEL;type=CELL;waid=${number}:${number}\nEND:VCARD` }]
      }
    }, { quoted })
  }
  
  sock.sendFile = async (to: string, file: string | Buffer, filename: string = '', caption: string = '', quoted?: any, ptt: boolean = false, options: any = {}) => {
    let fileBuffer: Buffer
    
    if (typeof file === 'string') {
      const response = await fetch(file)
      fileBuffer = Buffer.from(await response.arrayBuffer())
    } else {
      fileBuffer = file
    }

    const ext = filename.split('.').pop()?.toLowerCase() || ''
    const mimeTypes: { [key: string]: string } = {
  mp4: 'video/mp4', mkv: 'video/x-matroska', avi: 'video/x-msvideo',
  mp3: 'audio/mpeg', wav: 'audio/wav', ogg: 'audio/ogg',
  jpg: 'image/jpeg', jpeg: 'image/jpeg', png: 'image/png', gif: 'image/gif', webp: 'image/webp',
  pdf: 'application/pdf', doc: 'application/msword', docx: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  xls: 'application/vnd.ms-excel', xlsx: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
  ppt: 'application/vnd.ms-powerpoint', pptx: 'application/vnd.openxmlformats-officedocument.presentationml.presentation',
  txt: 'text/plain', zip: 'application/zip', rar: 'application/x-rar-compressed', '7z': 'application/x-7z-compressed'
}

    const mime = mimeTypes[ext] || 'application/octet-stream'
    const type = mime.split('/')[0]

    const mediaMessage: any = {
      [type === 'application' ? 'document' : type]: fileBuffer,
      mimetype: mime
    }

    if (filename && (type === 'application' || !['image', 'video', 'audio'].includes(type))) {
      mediaMessage.fileName = filename
    }

    if (ptt && type === 'audio') {
      mediaMessage.ptt = true
    }

    if (caption) {
      mediaMessage.caption = caption
    }

    await sock.sendMessage(to, mediaMessage, { ...options, quoted })
  }

  // Group Join
  sock.groupJoin = async (link: string) => {
    const inviteCode = link.split('chat.whatsapp.com/')[1]?.split('?')[0]
    return inviteCode ? await sock.groupAcceptInvite(inviteCode) : null
  }

  // Message with URL Preview
  sock.msgUrl = async (to: string, text: string, options: MsgUrlOptions, quoted?: any) => {
    const validatedOptions = MsgUrlOptionsSchema.parse(options)
    const messageOptions: any = { text, contextInfo: {} }
    
    if (validatedOptions.mentions) {
      messageOptions.contextInfo.mentionedJid = validatedOptions.mentions
    }
    
    if (validatedOptions.newsletter?.name || validatedOptions.newsletter?.jid) {
      messageOptions.contextInfo.isForwarded = true
      messageOptions.contextInfo.forwardingScore = 1
      messageOptions.contextInfo.forwardedNewsletterMessageInfo = {
        newsletterJid: validatedOptions.newsletter.jid || atob("MTIwMzYzMjI1MzU2ODM0MDQ0QG5ld3NsZXR0ZXI="),
        newsletterName: validatedOptions.newsletter.name || '𝐕𝐈𝐈7 ~ 𝐂𝐡𝐚𝐧𝐧𝐞𝐥 🕷️',
        serverMessageId: 0
      }
    }
    
    if (validatedOptions.img || validatedOptions.title || validatedOptions.body) {
      messageOptions.contextInfo.externalAdReply = {
        thumbnailUrl: typeof validatedOptions.img === 'string' ? validatedOptions.img : undefined,
        thumbnail: typeof validatedOptions.img === 'object' ? validatedOptions.img : undefined,
        title: validatedOptions.title || '',
        body: validatedOptions.body || '',
        mediaType: 1,
        renderLargerThumbnail: validatedOptions.big || false
      }
    }
    
    await sock.sendMessage(to, messageOptions, { quoted })
  }

  // Interactive Buttons
  sock.sendButton = async (to: string, options: SendInteractiveMessageOptions, quoted?: any) => {
    const validatedOptions = SendInteractiveMessageSchema.parse(options)
    
    const userJid = sock.authState?.creds?.me?.id || sock.user?.id
    let imageMessage = null

    if (validatedOptions.imageUrl) {
      try {
        const mediaUpload = await baileys.prepareWAMessageMedia(
          { image: { url: validatedOptions.imageUrl } },
          { upload: sock.waUploadToServer }
        )
        imageMessage = mediaUpload.imageMessage
      } catch (error: any) {
        console.error('Error uploading image:', error.message)
      }
    }

    const buttons = validatedOptions.buttons.map(button => ({
      name: button.name,
      buttonParamsJson: JSON.stringify(button.params)
    }))

    const contextInfo = createContextInfo(validatedOptions.mentions, validatedOptions.newsletter)
    const messageParams = createMessageParams(validatedOptions.footerText, validatedOptions.interactiveConfig)

    const messageContent = {
      interactiveMessage: {
        header: imageMessage ? { imageMessage, hasMediaAttachment: true } : undefined,
        body: { text: validatedOptions.bodyText || '' },
        contextInfo,
        nativeFlowMessage: { buttons, messageParamsJson: JSON.stringify(messageParams) }
      }
    }

    if (!imageMessage) delete messageContent.interactiveMessage.header

    const msg = generateWAMessageFromContent(to, messageContent, { userJid, quoted })

    return inM(to, sock, msg) /* await sock.relayMessage(to, msg.message, {
      messageId: msg.key.id,
      additionalNodes: [{
        tag: 'biz',
        attrs: {},
        content: [{
          tag: 'interactive',
          attrs: { type: 'native_flow', v: '1' },
          content: [{ tag: 'native_flow', attrs: { v: '9', name: 'mixed' } }]
        }]
      }]
    }) */
  }

  // Carousel with Buttons
  sock.sendCarousel = async (to: string, options: SendCarouselOptions, quoted?: any) => {
    const validatedOptions = SendCarouselSchema.parse(options)
    const userJid = sock.authState?.creds?.me?.id || sock.user?.id

    const generateImageMessage = async (url: string) => {
      const { imageMessage } = await generateWAMessageContent(
        { image: { url } },
        { upload: sock.waUploadToServer }
      )
      return imageMessage
    }

    const cards = []
    for (let i = 0; i < validatedOptions.cards.length; i++) {
      const card = validatedOptions.cards[i]
      
      cards.push({
        body: proto.Message.InteractiveMessage.Body.fromObject({
          text: card.bodyText || `${i + 1}`
        }),
        footer: proto.Message.InteractiveMessage.Footer.fromObject({
          text: card.footerText || validatedOptions.globalFooterText || '__'
        }),
        header: proto.Message.InteractiveMessage.Header.fromObject({
          title: '',
          hasMediaAttachment: true,
          imageMessage: await generateImageMessage(card.imageUrl)
        }),
        nativeFlowMessage: proto.Message.InteractiveMessage.NativeFlowMessage.fromObject({
          buttons: card.buttons?.map(btn => ({
            name: btn.name,
            buttonParamsJson: JSON.stringify(btn.params)
          })) || []
        })
      })
    }

    const contextInfo = createContextInfo(validatedOptions.mentions, validatedOptions.newsletter)

    const messageContent = generateWAMessageFromContent(to, {
      viewOnceMessage: {
        message: {
          messageContextInfo: {
            deviceListMetadata: {},
            deviceListMetadataVersion: 2
          },
          interactiveMessage: proto.Message.InteractiveMessage.fromObject({
            body: proto.Message.InteractiveMessage.Body.create({
              text: validatedOptions.headerText || ''
            }),
            footer: proto.Message.InteractiveMessage.Footer.create({
              text: validatedOptions.globalFooterText || '→'
            }),
            header: proto.Message.InteractiveMessage.Header.create({
              hasMediaAttachment: false
            }),
            contextInfo,
            carouselMessage: proto.Message.InteractiveMessage.CarouselMessage.fromObject({
              cards
            })
          })
        }
      }
    }, { quoted, userJid })

    return inM(to, sock, messageContent) /* await sock.relayMessage(to, messageContent.message, {
      messageId: messageContent.key.id,
      additionalNodes: [{
        tag: 'biz',
        attrs: {},
        content: [{
          tag: 'interactive',
          attrs: { type: 'native_flow', v: '1' },
          content: [{ tag: 'native_flow', attrs: { v: '9', name: 'mixed' } }]
        }]
      }]
    }) */
  }

  // Keys Message
  sock.KeysMessageWA = async () => {
    const key = await Utils.keyCore1()
    await Utils.keysMessagesObjWA(sock, key)
  }

  return sock
}