import {
  AnyMessageContent,
  WASocket,
  getContentType,
  jidNormalizedUser,
  downloadContentFromMessage,
  generateWAMessageFromContent,
  proto,
  WAMessage,
  GroupParticipant,
} from "@whiskeysockets/baileys";
import { z } from "zod";
import { Message } from "../types/types";

const M = proto.WebMessageInfo;

const OwnerSchema = z.object({
  jid: z.string().optional(),
  lid: z.string().optional(),
  name: z.string().optional(),
});
type Owner = z.infer<typeof OwnerSchema>;

const CustomGroupMetadataSchema = z.object({
  id: z.string().nullable().optional(),
  participants: z.array(
    z.object({
      id: z.string().optional(),
      admin: z.enum(["admin", "superadmin"]).nullable().optional(),
      phoneNumber: z.string().optional(),
    })
  ),
});
type CustomGroupMetadata = z.infer<typeof CustomGroupMetadataSchema>;

export type ExtendedMessage = Message & {
  isBaileys?: boolean;
  isBot?: boolean;
  groupMetadata?: CustomGroupMetadata;
  mtype?: string;
  msg?: any;
  mediaType?: string;
  isMedia?: boolean;
  mimetype?: string | null;
  fileSize?: number;
  fileName?: string | null;
  url?: string | null;
  directPath?: string | null;
  mediaKey?: Uint8Array | null;
  caption?: string | null;
  width?: number | null;
  height?: number | null;
  duration?: number | null;
  isViewOnce?: boolean;
  isForwarded?: boolean;
  forwardingScore?: number;
  isEdited?: boolean;
  editVersion?: number;
  quoted?: any;
  mentionedJid?: string[];
  getQuotedObj?: () => any;
  sendRead?: () => Promise<any>;
  copy?: () => any;
  copyNForward?: (
    jid: string,
    forceForward?: boolean,
    options?: Partial<AnyMessageContent>
  ) => Promise<any>;
  isButtonResponse?: boolean;
  buttonId?: string;
};

const extractMessageText = (msg: any): string => {
  const message = msg.message || msg;

  if (message.conversation) return message.conversation;
  if (message.extendedTextMessage?.text) return message.extendedTextMessage.text;
  if (message.imageMessage?.caption) return message.imageMessage.caption;
  if (message.videoMessage?.caption) return message.videoMessage.caption;
  if (message.documentMessage?.caption) return message.documentMessage.caption;
  if (message.documentWithCaptionMessage?.message?.documentMessage?.caption) {
    return message.documentWithCaptionMessage.message.documentMessage.caption;
  }

  if (message.buttonsResponseMessage) {
    return message.buttonsResponseMessage.selectedDisplayText || "";
  }

  if (message.listResponseMessage) {
    return message.listResponseMessage.title || "";
  }

  if (message.templateButtonReplyMessage) {
    return message.templateButtonReplyMessage.selectedDisplayText || "";
  }

  if (message.interactiveResponseMessage) {
    try {
      const json = JSON.parse(
        message.interactiveResponseMessage.nativeFlowResponseMessage.paramsJson
      );
      return json.displayText || json.id || "";
    } catch {
      return "";
    }
  }

  return "";
};

const extractButtonId = (rawMessage: WAMessage): string => {
  let buttonId = "";
  if (rawMessage.message?.buttonsResponseMessage) {
    buttonId = rawMessage.message.buttonsResponseMessage.selectedButtonId || "";
  } else if (rawMessage.message?.listResponseMessage) {
    buttonId =
      rawMessage.message.listResponseMessage.singleSelectReply?.selectedRowId || "";
  } else if (rawMessage.message?.templateButtonReplyMessage) {
    buttonId = rawMessage.message.templateButtonReplyMessage.selectedId || "";
  } else if (rawMessage.message?.interactiveResponseMessage) {
    try {
      const interactiveMsg = rawMessage.message.interactiveResponseMessage;
      if (interactiveMsg?.nativeFlowResponseMessage?.paramsJson) {
        const json = JSON.parse(interactiveMsg.nativeFlowResponseMessage.paramsJson);
        buttonId = json.id || "";
      }
    } catch {}
  }
  return buttonId;
};

const getGroupInfo = async (
  conn: WASocket,
  chat: string,
  sender: string
): Promise<{
  isAdmin: boolean;
  isBotAdmin: boolean;
  groupMetadata?: CustomGroupMetadata;
}> => {
  let isAdmin = false;
  let isBotAdmin = false;
  let groupMetadata: CustomGroupMetadata | undefined;

  try {
    const metadata = await conn.groupMetadata(chat);

    const botNumber = conn.user!.id.split(":")[0];
    const botJid = botNumber + "@s.whatsapp.net";
    const botLid = botNumber + "@lid";

    const senderParticipant = metadata.participants.find((p: GroupParticipant) =>
      [p.id, p.phoneNumber, (p as any).jid, (p as any).lid].includes(sender)
    );
    isAdmin = !!senderParticipant?.admin;

    const botParticipant = metadata.participants.find((p: GroupParticipant) =>
      [p.id, p.phoneNumber, (p as any).jid, (p as any).lid].includes(botJid) ||
      [p.id, p.phoneNumber, (p as any).jid, (p as any).lid].includes(botLid)
    );
    isBotAdmin = !!botParticipant?.admin;

    groupMetadata = {
      id: metadata.id,
      participants: metadata.participants.map((p: GroupParticipant) => ({
        id: p.id,
        admin: p.admin as "admin" | "superadmin" | null | undefined,
        phoneNumber: p.id.split("@")[0],
      })),
    };
  } catch (error) {
    console.error("Error fetching group metadata:", error);
  }

  return { isAdmin, isBotAdmin, groupMetadata };
};

const checkOwner = (owners: Owner[] | string[] | undefined, sender: string): boolean => {
  if (!owners) return false;
  return owners.some((owner) => {
    if (!owner) return false;
    if (typeof owner === "string") {
      return owner === sender || owner.split("@")[0] === sender.split("@")[0];
    }
    const ownerObj = owner as Owner;
    return (
      ownerObj.jid === sender ||
      ownerObj.lid === sender ||
      (ownerObj.lid && ownerObj.lid === sender.split("@")[0])
    );
  });
};

export const msgObj = async (
  rawMessage: WAMessage,
  conn: WASocket,
  owners?: Owner[] | string[],
  ctx?: any
): Promise<ExtendedMessage | null> => {
  if (!rawMessage || !conn.user?.id) return null;

  const messageText = extractMessageText(rawMessage);
  const buttonId = extractButtonId(rawMessage);
  const isButtonResponse = !!buttonId && buttonId !== messageText;
  const finalBody = isButtonResponse ? buttonId : messageText;

  const sender = rawMessage.key?.fromMe
    ? jidNormalizedUser(conn.user.id)
    : jidNormalizedUser(
        rawMessage.key?.participantAlt ||
          rawMessage.key?.remoteJidAlt ||
          rawMessage.key?.participant ||
          ""
      );

  const chat = rawMessage.key?.remoteJid || "";
  const isGroup = chat.endsWith("@g.us");

  const isOwner = checkOwner(owners, sender);

  let isAdmin = false;
  let isBotAdmin = false;
  let groupMetadata: CustomGroupMetadata | undefined;

  if (isGroup && chat) {
    const groupInfo = await getGroupInfo(conn, chat, sender);
    isAdmin = groupInfo.isAdmin;
    isBotAdmin = groupInfo.isBotAdmin;
    groupMetadata = groupInfo.groupMetadata;
  }

  const baseMessage: Message = {
    id: rawMessage.key?.id ?? undefined,
    body: finalBody,
    text: messageText,
    from: chat,
    name: rawMessage.pushName || "Unknown",
    timestamp: new Date(((rawMessage.messageTimestamp as number) || 0) * 1000),
    isGroup,
    isOwner,
    isAdmin,
    isBotAdmin,
    fromMe: rawMessage.key?.fromMe! || false,
    raw: rawMessage,
    chat,
    sender,
    pushName: rawMessage.pushName ?? undefined,
    key: rawMessage.key,
    message: rawMessage.message,
    client: () => {
    return conn;
},
    reply: async (text: string, options?: Partial<AnyMessageContent>) => {
      if (!chat) throw new Error("No chat specified");
      return conn.sendMessage(
        chat,
        {
          text,
          contextInfo: {
            mentionedJid: [sender],
            isForwarded: true,
            forwardingScore: 1,
            forwardedNewsletterMessageInfo: {
              newsletterJid: ctx?.["config"]?.info?.idChannel,
              newsletterName: ctx?.["config"]?.info?.nameChannel,
              serverMessageId: 0,
            },
          },
        },
        { quoted: rawMessage, ...options }
      );
    },
    reply2: async (text: string, options?: Partial<AnyMessageContent>) => {
      if (!chat) throw new Error("No chat specified");
      return conn.sendMessage(chat, { text }, { quoted: rawMessage, ...options });
    },
    react: async (emoji: string): Promise<any> => {
      if (!chat || !rawMessage.key) return;
      return conn.sendMessage(chat, {
        react: {
          text: emoji,
          key: rawMessage.key,
        },
      });
    },
    lid2jid: async (id: string): Promise<any> => {
      try {
        const metadata = await conn.groupMetadata(chat);
        return metadata.participants.find((x) => x.id == id)?.phoneNumber;
      } catch {
        return null;
      }
    },
    jid2lid: async (num: string): Promise<any> => {
      try {
        const metadata = await conn.groupMetadata(chat);
        return metadata.participants.find((x) => x.phoneNumber == num)?.id;
      } catch {
        return null;
      }
    },
    delete: async (): Promise<any> => {
      if (!rawMessage.key || !chat) return;
      return conn.sendMessage(chat, {
        delete: {
          id: rawMessage.key.id!,
          participant: rawMessage.key.participant,
          remoteJid: chat,
        },
      });
    },
    download: async (): Promise<Buffer | null> => {
      try {
        if (!rawMessage.message) return null;
        const mtype = getContentType(rawMessage.message);
        if (!mtype) return null;

        const msgContent = (rawMessage.message as any)[mtype];
        if (!msgContent) return null;

        const mediaType = mtype.replace("Message", "") as any;
        const stream = await downloadContentFromMessage(msgContent, mediaType);
        let buffer = Buffer.from([]);
        for await (const chunk of stream) {
          buffer = Buffer.concat([buffer, chunk]);
        }
        return buffer;
      } catch {
        return null;
      }
    },
    forward: async (jid: string, options: Partial<AnyMessageContent> = {}): Promise<any> => {
      return conn.sendMessage(jid, {
        forward: rawMessage,
        ...options,
      });
    },
    typing: async (duration = 3000): Promise<void> => {
      if (!chat) return;
      await conn.sendPresenceUpdate("composing", chat);
      setTimeout(async () => {
        await conn.sendPresenceUpdate("paused", chat);
      }, duration);
    },
    recording: async (duration = 3000): Promise<void> => {
      if (!chat) return;
      await conn.sendPresenceUpdate("recording", chat);
      setTimeout(async () => {
        await conn.sendPresenceUpdate("paused", chat);
      }, duration);
    },
  };

  const m: ExtendedMessage = {
    ...baseMessage,
    isBaileys: baseMessage.id?.startsWith("BAE5") && baseMessage.id?.length === 16,
    isBot: baseMessage.id?.startsWith("3EB0") && baseMessage.id?.length === 12,
    groupMetadata,
    isButtonResponse,
    buttonId: buttonId || undefined,
  };

  if (rawMessage.message) {
    m.mtype = getContentType(rawMessage.message);

    if (m.mtype) {
      const messageObj = rawMessage.message as any;
      m.msg = messageObj[m.mtype];

      if (
        m.mtype === "viewOnceMessage" ||
        m.mtype === "viewOnceMessageV2" ||
        m.mtype === "viewOnceMessageV2Extension"
      ) {
        const innerMessage = m.msg?.message;
        if (innerMessage) {
          const innerType = getContentType(innerMessage);
          if (innerType) {
            m.msg = (innerMessage as any)[innerType];
            m.mtype = innerType;
          }
        }
      }
    }

    m.mediaType = m.mtype?.replace("Message", "");
    m.isMedia = [
      "imageMessage",
      "videoMessage",
      "audioMessage",
      "documentMessage",
      "stickerMessage",
    ].includes(m.mtype || "");

    if (m.isMedia && m.msg) {
      m.mimetype = m.msg.mimetype || null;
      m.fileSize = m.msg.fileLength || 0;
      m.fileName = m.msg.fileName || null;
      m.url = m.msg.url || null;
      m.directPath = m.msg.directPath || null;
      m.mediaKey = m.msg.mediaKey || null;
      m.caption = m.msg.caption || null;
    }

    if (
      m.mtype === "imageMessage" ||
      m.mtype === "videoMessage" ||
      m.mtype === "stickerMessage"
    ) {
      m.width = m.msg.width || null;
      m.height = m.msg.height || null;
    }

    if (m.mtype === "videoMessage" || m.mtype === "audioMessage") {
      m.duration = m.msg.seconds || m.msg.duration || null;
    }

    m.isViewOnce =
      m.mtype === "viewOnceMessage" ||
      m.mtype === "viewOnceMessageV2" ||
      m.msg?.viewOnce === true;

    m.isForwarded = m.msg?.contextInfo?.isForwarded || false;
    m.forwardingScore = m.msg?.contextInfo?.forwardingScore || 0;

    if (m.msg?.contextInfo?.quotedMessage?.protocolMessage?.type === 0) {
      m.isEdited = true;
      m.editVersion = m.msg.contextInfo.quotedMessage.protocolMessage.editVersion || 0;
    }

    m.mentionedJid = m.msg?.contextInfo?.mentionedJid || [];

    if (m.msg?.contextInfo?.quotedMessage) {
      const quoted = m.msg.contextInfo.quotedMessage;
      const qtype = getContentType(quoted);
      let qmsg: any = null;

      if (qtype) {
        qmsg = (quoted as any)[qtype];
      }

      const qIsMedia = qtype
        ? [
            "imageMessage",
            "videoMessage",
            "audioMessage",
            "documentMessage",
            "stickerMessage",
          ].includes(qtype)
        : false;

      const quotedObj: any = {
        mtype: qtype,
        id: m.msg.contextInfo.stanzaId,
        chat: m.msg.contextInfo.remoteJid || m.chat,
        sender: m.msg.contextInfo.participant
          ? m.msg.contextInfo.participantAlt || jidNormalizedUser(m.msg.contextInfo.participant)
          : "",
        fromMe: m.msg.contextInfo.participant
          ? jidNormalizedUser(m.msg.contextInfo.participant) === jidNormalizedUser(conn.user!.id)
          : false,
        text:
          typeof qmsg === "string" ? qmsg : false ||
          qmsg?.text ||
          qmsg?.caption ||
          qmsg?.conversation ||
          qmsg?.selectedDisplayText ||
          qmsg?.hydratedTemplate?.hydratedContentText ||
          "",
        massage: typeof qmsg === "object" ? qmsg : false,
        mediaType: qtype?.replace("Message", ""),
        isMedia: qIsMedia,
        mentionedJid: m.msg.contextInfo.mentionedJid || [],
      };

      if (qIsMedia && qmsg) {
        quotedObj.mimetype = qmsg.mimetype || null;
        quotedObj.fileSize = qmsg.fileLength || 0;
        quotedObj.fileName = qmsg.fileName || null;
        quotedObj.width = qmsg.width || null;
        quotedObj.height = qmsg.height || null;
        quotedObj.duration = qmsg.seconds || qmsg.duration || null;
        quotedObj.url = qmsg.url || null;
        quotedObj.directPath = qmsg.directPath || null;
        quotedObj.mediaKey = qmsg.mediaKey || null;
        quotedObj.thumbnailUrl = qmsg.thumbnailDirectPath || null;
      }

      quotedObj.fakeObj = (): any => {
        const fakeMessage = {
          key: {
            remoteJid: m.msg.contextInfo.remoteJid || m.chat,
            fromMe: quotedObj.fromMe,
            id: m.msg.contextInfo.stanzaId,
            participant: m.msg.contextInfo.participant,
          },
          message: quoted,
        };

        if (m.isGroup) {
          (fakeMessage as any).participant = m.msg.contextInfo.participant;
        }

        return M.fromObject(fakeMessage);
      };

      quotedObj.download = async (): Promise<Buffer | null> => {
        try {
          if (!qmsg || !qtype) return null;
          const mediaType = qtype.replace("Message", "") as any;
          const stream = await downloadContentFromMessage(qmsg, mediaType);
          let buffer = Buffer.from([]);
          for await (const chunk of stream) {
            buffer = Buffer.concat([buffer, chunk]);
          }
          return buffer;
        } catch {
          return null;
        }
      };

      quotedObj.delete = async (): Promise<any> => {
        if (!m.msg?.contextInfo?.stanzaId) return;
        return conn.sendMessage(
          m.msg.contextInfo.remoteJid || m.chat || "",
          {
            delete: {
              id: m.msg.contextInfo.stanzaId,
              participant: m.msg.contextInfo.participant,
              remoteJid: m.msg.contextInfo.remoteJid || m.chat,
            },
          }
        );
      };

      quotedObj.react = async (emoji: string): Promise<any> => {
        if (!m.msg?.contextInfo?.stanzaId) return;
        return conn.sendMessage(
          m.msg.contextInfo.remoteJid || m.chat || "",
          {
            react: {
              text: emoji,
              key: {
                remoteJid: m.msg.contextInfo.remoteJid || m.chat,
                fromMe: quotedObj.fromMe,
                id: m.msg.contextInfo.stanzaId,
                participant: m.msg.contextInfo.participant,
              },
            },
          }
        );
      };

      quotedObj.reply = async (
        text: string,
        options: Partial<AnyMessageContent> = {}
      ): Promise<any> => {
        return conn.sendMessage(
          m.msg.contextInfo.remoteJid || m.chat || "",
          { text },
          { quoted: quotedObj.fakeObj!(), ...options }
        );
      };

      quotedObj.forward = async (
        jid: string,
        options: Partial<AnyMessageContent> = {}
      ): Promise<any> => {
        return conn.sendMessage(jid, {
          forward: quotedObj.fakeObj!(),
          ...options,
        });
      };

      quotedObj.copy = (): any => {
        const obj = quotedObj.fakeObj!();
        return M.fromObject(M.toObject(obj));
      };

      m.quoted = quotedObj;
      m.getQuotedObj = quotedObj.fakeObj;
    }
  }

  m.sendRead = async (): Promise<any> => {
    if (!rawMessage.key || !m.chat) return;
    return conn.sendReceipt(m.chat, rawMessage.key.participant || undefined, [m.id!], "read");
  };

  m.copy = (): any => {
    return M.fromObject(M.toObject(rawMessage as any));
  };

  m.copyNForward = async (
    jid: string,
    forceForward = false,
    options: Partial<AnyMessageContent> = {}
  ): Promise<any> => {
    try {
      if (
        forceForward ||
        !rawMessage.message ||
        getContentType(rawMessage.message) === "conversation"
      ) {
        return conn.sendMessage(jid, { forward: rawMessage, ...options });
      }

      const message = generateWAMessageFromContent(jid, rawMessage.message, {
        ...options,
        userJid: conn.user!.id,
      });

      await conn.relayMessage(jid, message.message!, {
        messageId: message.key.id!,
        ...(options as any),
      });

      return message;
    } catch {
      return conn.sendMessage(jid, { forward: rawMessage, ...options });
    }
  };

  return m;
};