import axios from "axios";

const CONFIG: any = {
  audio: { ext: ["mp3", "m4a", "wav", "opus", "flac"], q: ["best", "320k", "128k"] },
  video: { ext: ["mp4"], q: ["144p", "240p", "360p", "480p", "720p", "1080p"] }
};

const HEADERS: any = {
  accept: "application/json",
  "content-type": "application/json",
  "user-agent": "Mozilla/5.0 (Android)",
  referer: "https://ytmp3.gg/"
};

const API: any = {
  ENDPOINTS: ["https://hub.ytconvert.org/api/download", "https://api.ytconvert.org/api/download"],
  POLL_INTERVAL: 2000
};

const poll = async (statusUrl: string): Promise<any> => {
  const { data } = await axios.get(statusUrl, { headers: HEADERS });
  if (data.status === "completed") return data;
  if (data.status === "failed") throw new Error(data.message || "Conversion failed");
  await new Promise(r => setTimeout(r, API.POLL_INTERVAL));
  return poll(statusUrl);
};

const validate = {
  format: (format: string): string | undefined => {
    return Object.keys(CONFIG).find(k => CONFIG[k].ext.includes(format));
  },
  quality: (type: string, quality: string): boolean => {
    return type && CONFIG[type]?.q?.includes(quality) || false;
  }
};

const fetchWithFallback = async (payload: any): Promise<any> => {
  for (const endpoint of API.ENDPOINTS) {
    try {
      return await axios.post(endpoint, payload, { headers: HEADERS });
    } catch {
      continue;
    }
  }
  throw new Error("All converter endpoints failed");
};

const createPayload = (url: string, type: string, format: string, quality: string): any => ({
  url,
  os: "android",
  output: { type, format },
  ...(type === "video" && { quality }),
  ...(type === "audio" && { audio: { bitrate: quality } })
});

async function convertYouTube(url: string, format: string = "mp3", quality: string = "128k"): Promise<any> {
  try {
    const type = validate.format(format);
    if (!type) throw new Error(`Unsupported format: ${format}`);
    if (!validate.quality(type, quality)) {
      throw new Error(`Invalid quality. Choose: ${CONFIG[type]?.q?.join(", ") || "unknown"}`);
    }

    const { data: meta } = await axios.get("https://www.youtube.com/oembed", {
      params: { url, format: "json" }
    });

    const payload = createPayload(url, type, format, quality);
    const { data: initData } = await fetchWithFallback(payload);
    
    if (!initData?.statusUrl) {
      throw new Error("No status URL received");
    }

    const result = await poll(initData.statusUrl);
    const cleanTitle = meta.title.replace(/[^\w\s-]/gi, '');

    return {
      title: meta.title,
      author: meta.author_name,
      duration: result.duration || "Unknown",
      thumbnail: meta.thumbnail_url,
      downloadUrl: result.downloadUrl,
      format,
      quality,
      filename: `${cleanTitle}.${format}`
    };
  } catch (err: any) {
    return { status: false, message: err.message };
  }
}

const formatResponse = (result: any, type: string, quality: string | null = null): any => {
  if (result?.status === false) return result;
  
  const base = {
    status: true,
    creator: "@VENi_VII7",
    title: result.title,
    channel: result.author,
    duration: result.duration,
    thumbnail: result.thumbnail,
    downloadUrl: result.downloadUrl,
    filename: result.filename
  };

  return type === 'mp3' 
    ? { ...base, quality: "128kbps" }
    : { 
        ...base, 
        quality_list: { [quality!]: { resolution: quality, url: result.downloadUrl } }
      };
};

const validateUrl = (url: string): any => {
  if (!url) return { status: false, message: "YouTube URL is required" };
  return null;
};
