async function AnimeGif(type: string): Promise<any> {
return (await fetch(`https://nekos.best/api/v2/${type}`)).json()
}


async function ytmp3(url: string): Promise<any> {
  const error = validateUrl(url);
  if (error) return error;
  const result = await convertYouTube(url, "mp3", "128k");
  return formatResponse(result, 'mp3');
}

async function ytmp4(url: string, quality: string = "720p"): Promise<any> {
  const error = validateUrl(url);
  if (error) return error;
  const result = await convertYouTube(url, "mp4", quality);
  return formatResponse(result, 'mp4', quality);
}

const ConvertYt: any = { ytmp3, ytmp4, AnimeGif };
export default ConvertYt;