import {
  proto,
  WAMessage
} from "@whiskeysockets/baileys";
import { Message } from "../types/types";
import { msgObj } from "../r-enhancers/index.js";
import { print } from "../utils/index.js";

type MessagesUpsertEvent = {
  messages: proto.IWebMessageInfo[];
  type: string;
};

const EXCLUDED_MESSAGE_TYPES = {
  protocolMessage: 'protocolMessage',
  senderKeyDistributionMessage: 'senderKeyDistributionMessage',
  stickerSyncRmrMessage: 'stickerSyncRmrMessage'
};

const isValidMessage = (msg: proto.IWebMessageInfo): boolean => {
  if (!msg.message) return false;
  return !(msg.message.protocolMessage ||
          msg.message.senderKeyDistributionMessage ||
          msg.message.stickerSyncRmrMessage);
};

const processHandlers = async (messageObj: any, ctx: any): Promise<boolean> => {
  for (const handler of ctx.handlers) {
    try {
      const response = await handler(messageObj);
      if (response) {
        if (typeof response === 'string') {
          await messageObj.reply(response);
        } else if (typeof response === 'object') {
          await messageObj.reply(response.text || '', response);
        }
        return true;
      }
    } catch (error) {
      if (ctx.config.onError && typeof ctx.config.onError === 'function') {
        ctx.config.onError(error);
      }
    }
  }
  return false;
};

const message_event = (ctx: any) => {
  if (!ctx.sock) return;

  ctx.sock.ev.on('messages.upsert', async ({ messages, type }: MessagesUpsertEvent) => {
    if (type !== 'notify') return;

    print(messages, ctx);

    for (const msg of messages) {
      try {
        if (!isValidMessage(msg)) continue;

        if (ctx.config.autoRead) {
          await ctx.sock.readMessages([msg.key]).catch(() => {});
        }

        const messageObj = await msgObj(msg as WAMessage, ctx.sock, ctx.config.owners, ctx);
        if (!messageObj) continue;

        if (ctx.config.fromMe === true && !messageObj.fromMe) continue;
        if (ctx.config.fromMe === false && messageObj.fromMe) continue;

        const processed = await ctx.commandSystem.processMessage(messageObj, ctx, ctx.config.prefix);

        if (!processed) {
          await processHandlers(messageObj, ctx);
        }
      } catch (error) {
        if (ctx.config.onError && typeof ctx.config.onError === 'function') {
          ctx.config.onError(error);
        }
      }
    }
  });
};

export default message_event;