async function getMediaSize(msg: WAMessage): Promise<number> {
    try {
        const content = msg.message;
        if (!content) return 0;
        const type = getContentType(content);
        if (!type) return 0;
        const media = content[type as keyof typeof content] as any;
        if (!media) return 0;
        if (media.fileLength) return Number(media.fileLength);
        if (media.directPath) {
            const stream = await downloadContentFromMessage(media, type.replace('Message', '') as any);
            let size = 0;
            for await (const chunk of stream) {
                size += chunk.length;
            }
            return size;
        }
        return 0;
    } catch {
        return 0;
    }
}

function getMediaDimensions(msg: WAMessage): { width: number; height: number; seconds?: number } {
    try {
        const content = msg.message;
        if (!content) return { width: 0, height: 0 };
        const type = getContentType(content);
        if (!type) return { width: 0, height: 0 };
        const media = content[type as keyof typeof content] as any;
        return {
            width: media?.width || 0,
            height: media?.height || 0,
            seconds: media?.seconds || media?.duration || undefined
        };
    } catch {
        return { width: 0, height: 0 };
    }
}

function getMediaMimetype(msg: WAMessage): string {
    try {
        const content = msg.message;
        if (!content) return '';
        const type = getContentType(content);
        if (!type) return '';
        const media = content[type as keyof typeof content] as any;
        return media?.mimetype || media?.mimeType || '';
    } catch {
        return '';
    }
}

function getMediaFilename(msg: WAMessage): string {
    try {
        const content = msg.message;
        if (!content) return 'file';
        const type = getContentType(content);
        if (!type) return 'file';
        const media = content[type as keyof typeof content] as any;
        if (media?.fileName) return media.fileName;
        if (type === 'imageMessage') return 'image.jpg';
        if (type === 'videoMessage') return 'video.mp4';
        if (type === 'audioMessage') return 'audio.mp3';
        if (type === 'documentMessage') return media?.fileName || 'document.pdf';
        if (type === 'stickerMessage') return 'sticker.webp';
        return `file.${getExtensionFromMime(media?.mimetype || '')}`;
    } catch {
        return 'file';
    }
}

function extractUrl(text: string): string[] {
    const urlRegex = /(https?:\/\/[^\s]+)/g;
    return text.match(urlRegex) || [];
}

function extractMentionedJids(text: string): string[] {
    const mentionRegex = /@(\d+)/g;
    const matches = text.match(mentionRegex) || [];
    return matches.map(m => m.replace('@', '') + '@s.whatsapp.net');
}

function extractQuotedText(msg: WAMessage): string {
    try {
        const quoted = msg.message?.extendedTextMessage?.contextInfo?.quotedMessage;
        if (!quoted) return '';
        if (quoted.conversation) return quoted.conversation;
        if (quoted.extendedTextMessage?.text) return quoted.extendedTextMessage.text;
        if (quoted.imageMessage?.caption) return quoted.imageMessage.caption;
        if (quoted.videoMessage?.caption) return quoted.videoMessage.caption;
        if (quoted.documentMessage?.caption) return quoted.documentMessage.caption;
        return '';
    } catch {
        return '';
    }
}

