function getMessageType(msg: WAMessage): string {
    try {
        const content = msg.message;
        if (!content) return 'unknown';
        const type = getContentType(content);
        if (!type) return 'unknown';
        return type.replace('Message', '').toLowerCase();
    } catch {
        return 'unknown';
    }
}

