class CacheManager {
    private cache: Map<string, { value: any; expiry: number }> = new Map();
    set(key: string, value: any, ttl: number = 3600): void {
        const expiry = Date.now() + (ttl * 1000);
        this.cache.set(key, { value, expiry });
    }
    get(key: string): any {
        const item = this.cache.get(key);
        if (!item) return null;
        if (Date.now() > item.expiry) {
            this.cache.delete(key);
            return null;
        }
        return item.value;
    }
    has(key: string): boolean {
        const item = this.cache.get(key);
        if (!item) return false;
        if (Date.now() > item.expiry) {
            this.cache.delete(key);
            return false;
        }
        return true;
    }
    delete(key: string): boolean {
        return this.cache.delete(key);
    }
    clear(): void {
        this.cache.clear();
    }
    size(): number {
        this.cleanup();
        return this.cache.size;
    }
    keys(): string[] {
        this.cleanup();
        return Array.from(this.cache.keys());
    }
    values(): any[] {
        this.cleanup();
        return Array.from(this.cache.values()).map(v => v.value);
    }
    private cleanup(): void {
        const now = Date.now();
        for (const [key, item] of this.cache.entries()) {
            if (now > item.expiry) {
                this.cache.delete(key);
            }
        }
    }
}

class QueueManager<T> {
    private queue: T[] = [];
    private processing: boolean = false;
    private handlers: Map<string, (item: T) => Promise<void>> = new Map();
    add(item: T): void {
        this.queue.push(item);
        if (!this.processing) {
            this.process();
        }
    }
    addMany(items: T[]): void {
        this.queue.push(...items);
        if (!this.processing) {
            this.process();
        }
    }
    registerHandler(type: string, handler: (item: T) => Promise<void>): void {
        this.handlers.set(type, handler);
    }
    size(): number {
        return this.queue.length;
    }
    clear(): void {
        this.queue = [];
    }
    private async process(): Promise<void> {
        if (this.queue.length === 0) {
            this.processing = false;
            return;
        }
        this.processing = true;
        const item = this.queue.shift();
        if (item && this.handlers.has('default')) {
            await this.handlers.get('default')!(item);
        }
        setImmediate(() => this.process());
    }
}

class RateLimiter {
    private limits: Map<string, { count: number; resetTime: number }> = new Map();
    constructor(private maxRequests: number, private timeWindow: number) {}
    check(key: string): boolean {
        const now = Date.now();
        const limit = this.limits.get(key);
        if (!limit) {
            this.limits.set(key, {
                count: 1,
                resetTime: now + this.timeWindow
            });
            return true;
        }
        if (now > limit.resetTime) {
            this.limits.set(key, {
                count: 1,
                resetTime: now + this.timeWindow
            });
            return true;
        }
        if (limit.count >= this.maxRequests) {
            return false;
        }
        limit.count++;
        return true;
    }
    getRemaining(key: string): number {
        const limit = this.limits.get(key);
        if (!limit) return this.maxRequests;
        if (Date.now() > limit.resetTime) {
            return this.maxRequests;
        }
        return Math.max(0, this.maxRequests - limit.count);
    }
    getResetTime(key: string): number | null {
        const limit = this.limits.get(key);
        return limit ? limit.resetTime : null;
    }
    reset(key: string): void {
        this.limits.delete(key);
    }
    resetAll(): void {
        this.limits.clear();
    }
}

enum LogLevel {
    DEBUG = 0,
    INFO = 1,
    WARN = 2,
    ERROR = 3,
    NONE = 4
}

class Logger {
    private level: LogLevel = LogLevel.INFO;
    private context: string = 'App';
    constructor(context?: string, level?: LogLevel) {
        if (context) this.context = context;
        if (level !== undefined) this.level = level;
    }
    setLevel(level: LogLevel): void {
        this.level = level;
    }
    debug(message: string, ...args: any[]): void {
        if (this.level <= LogLevel.DEBUG) {
            console.log(`[${this.getTimestamp()}] [${this.context}] [DEBUG]`, message, ...args);
        }
    }
    info(message: string, ...args: any[]): void {
        if (this.level <= LogLevel.INFO) {
            console.log(`[${this.getTimestamp()}] [${this.context}] [INFO]`, message, ...args);
        }
    }
    warn(message: string, ...args: any[]): void {
        if (this.level <= LogLevel.WARN) {
            console.warn(`[${this.getTimestamp()}] [${this.context}] [WARN]`, message, ...args);
        }
    }
    error(message: string, ...args: any[]): void {
        if (this.level <= LogLevel.ERROR) {
            console.error(`[${this.getTimestamp()}] [${this.context}] [ERROR]`, message, ...args);
        }
    }
    private getTimestamp(): string {
        return new Date().toISOString();
    }
}

class ConfigManager {
    private config: Map<string, any> = new Map();
    private defaults: Map<string, any> = new Map();
    set(key: string, value: any): void {
        this.config.set(key, value);
    }
    get(key: string): any {
        return this.config.has(key) ? this.config.get(key) : this.defaults.get(key);
    }
    setDefault(key: string, value: any): void {
        this.defaults.set(key, value);
    }
    has(key: string): boolean {
        return this.config.has(key) || this.defaults.has(key);
    }
    delete(key: string): boolean {
        return this.config.delete(key);
    }
    loadFromObject(obj: object): void {
        Object.entries(obj).forEach(([key, value]) => {
            this.set(key, value);
        });
    }
    loadFromEnv(prefix: string = ''): void {
        Object.keys(process.env).forEach(key => {
            if (prefix && !key.startsWith(prefix)) return;
            this.set(key, process.env[key]);
        });
    }
    toObject(): object {
        const obj: any = {};
        this.config.forEach((value, key) => {
            obj[key] = value;
        });
        return obj;
    }
    merge(config: ConfigManager): void {
        config.toObject();
        this.loadFromObject(config.toObject());
    }
    reset(): void {
        this.config.clear();
    }
}

class StatsCollector {
    private stats: Map<string, { count: number; total: number; min: number; max: number }> = new Map();
    add(key: string, value: number): void {
        const stat = this.stats.get(key) || { count: 0, total: 0, min: Infinity, max: -Infinity };
        stat.count++;
        stat.total += value;
        stat.min = Math.min(stat.min, value);
        stat.max = Math.max(stat.max, value);
        this.stats.set(key, stat);
    }
    increment(key: string, by: number = 1): void {
        this.add(key, by);
    }
    get(key: string): { count: number; sum: number; avg: number; min: number; max: number } {
        const stat = this.stats.get(key);
        if (!stat) {
            return { count: 0, sum: 0, avg: 0, min: 0, max: 0 };
        }
        return {
            count: stat.count,
            sum: stat.total,
            avg: stat.total / stat.count,
            min: stat.min,
            max: stat.max
        };
    }
    getAll(): object {
        const result: any = {};
        this.stats.forEach((value, key) => {
            result[key] = this.get(key);
        });
        return result;
    }
    reset(key?: string): void {
        if (key) {
            this.stats.delete(key);
        } else {
            this.stats.clear();
        }
    }
}

class Timer {
    private startTime: number | null = null;
    private endTime: number | null = null;
    private laps: number[] = [];
    start(): void {
        this.startTime = Date.now();
        this.endTime = null;
        this.laps = [];
    }
    stop(): number {
        if (!this.startTime) return 0;
        this.endTime = Date.now();
        return this.endTime - this.startTime;
    }
    lap(): number {
        if (!this.startTime) return 0;
        const now = Date.now();
        const lapTime = now - (this.laps.length ? this.laps[this.laps.length - 1] : this.startTime);
        this.laps.push(now);
        return lapTime;
    }
    reset(): void {
        this.startTime = null;
        this.endTime = null;
        this.laps = [];
    }
    getElapsed(): number {
        if (!this.startTime) return 0;
        if (this.endTime) return this.endTime - this.startTime;
        return Date.now() - this.startTime;
    }
    getLaps(): number[] {
        const laps: number[] = [];
        let prev = this.startTime;
        for (const lap of this.laps) {
            laps.push(lap - prev!);
            prev = lap;
        }
        return laps;
    }
}

function throttle<T extends (...args: any[]) => any>(func: T, limit: number): (...args: Parameters<T>) => void {
    let inThrottle: boolean = false;
    return function(this: any, ...args: Parameters<T>) {
        if (!inThrottle) {
            func.apply(this, args);
            inThrottle = true;
            setTimeout(() => inThrottle = false, limit);
        }
    };
}

function debounce<T extends (...args: any[]) => any>(func: T, delay: number): (...args: Parameters<T>) => void {
    let timeoutId: NodeJS.Timeout;
    return function(this: any, ...args: Parameters<T>) {
        clearTimeout(timeoutId);
        timeoutId = setTimeout(() => func.apply(this, args), delay);
    };
}

function memoize<T extends (...args: any[]) => any>(func: T, resolver?: (...args: Parameters<T>) => string): T {
    const cache = new Map<string, ReturnType<T>>();
    return function(this: any, ...args: Parameters<T>): ReturnType<T> {
        const key = resolver ? resolver.apply(this, args) : JSON.stringify(args);
        if (cache.has(key)) {
            return cache.get(key)!;
        }
        const result = func.apply(this, args);
        cache.set(key, result);
        return result;
    } as T;
}

